import{_ as t,o as h,c as i,a0 as a}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Sản xuất","description":"","frontmatter":{"title":"Sản xuất","sidebar_position":3},"headers":[],"relativePath":"manufacturing.md","filePath":"manufacturing.md"}'),c={name:"manufacturing.md"};function o(u,n,l,r,e,g){return h(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="san-xuat" tabindex="-1">Sản xuất <a class="header-anchor" href="#san-xuat" aria-label="Permalink to &quot;Sản xuất&quot;">​</a></h1><p>Mô-đun Sản xuất trong ABNERP quản lý toàn bộ quy trình sản xuất từ khâu lập kế hoạch, quản lý định mức nguyên vật liệu, theo dõi tiến độ sản xuất cho đến kiểm soát chất lượng. Đây là công cụ mạnh mẽ cho các doanh nghiệp sản xuất, giúp tối ưu hóa năng lực sản xuất và giảm thiểu lãng phí.</p><h2 id="đinh-muc-nguyen-vat-lieu-bill-of-materials-—-bom" tabindex="-1">Định mức nguyên vật liệu (Bill of Materials — BOM) <a class="header-anchor" href="#đinh-muc-nguyen-vat-lieu-bill-of-materials-—-bom" aria-label="Permalink to &quot;Định mức nguyên vật liệu (Bill of Materials — BOM)&quot;">​</a></h2><p>BOM là thành phần cốt lõi của mô-đun Sản xuất, xác định danh sách nguyên vật liệu và quy trình cần thiết để sản xuất một thành phẩm. ABNERP hỗ trợ BOM nhiều cấp, cho phép định nghĩa cấu trúc sản phẩm phức tạp với các bán thành phẩm ở nhiều cấp độ khác nhau. Bạn có thể thiết lập nhiều BOM cho cùng một sản phẩm để phục vụ các mục đích sản xuất khác nhau. Hệ thống tự động tính toán chi phí nguyên vật liệu dựa trên BOM và giá hiện tại.</p><h2 id="lenh-san-xuat-production-order" tabindex="-1">Lệnh sản xuất (Production Order) <a class="header-anchor" href="#lenh-san-xuat-production-order" aria-label="Permalink to &quot;Lệnh sản xuất (Production Order)&quot;">​</a></h2><p>Lệnh sản xuất được tạo từ đơn bán hàng, từ kế hoạch sản xuất hoặc thủ công. Mỗi lệnh sản xuất xác định sản phẩm cần sản xuất, số lượng, thời gian bắt đầu và kết thúc dự kiến. Khi lệnh sản xuất được thực thi, hệ thống sẽ khấu trừ nguyên vật liệu từ kho và ghi nhận thành phẩm nhập kho. Bạn có thể theo dõi tiến độ từng lệnh sản xuất theo thời gian thực.</p><h2 id="phieu-cong-viec-job-card" tabindex="-1">Phiếu công việc (Job Card) <a class="header-anchor" href="#phieu-cong-viec-job-card" aria-label="Permalink to &quot;Phiếu công việc (Job Card)&quot;">​</a></h2><p>Phiếu công việc ghi lại chi tiết hoạt động sản xuất cho từng công đoạn hoặc từng công nhân. Công nhân có thể bắt đầu/kết thúc phiếu công việc, ghi nhận thời gian làm việc, số lượng sản phẩm hoàn thành và sản phẩm lỗi. Dữ liệu này được sử dụng để tính lương theo sản phẩm, đánh giá năng suất và phân tích hiệu quả sản xuất.</p><h2 id="tram-lam-viec-workstation" tabindex="-1">Trạm làm việc (Workstation) <a class="header-anchor" href="#tram-lam-viec-workstation" aria-label="Permalink to &quot;Trạm làm việc (Workstation)&quot;">​</a></h2><p>Trạm làm việc đại diện cho các máy móc, thiết bị hoặc vị trí làm việc trong nhà máy. Bạn có thể cấu hình năng lực sản xuất, lịch bảo trì và chi phí vận hành cho từng trạm. Hệ thống hỗ trợ lập lịch sản xuất tự động dựa trên năng lực khả dụng của các trạm làm việc, giúp tối ưu hóa việc sử dụng tài nguyên và tránh tình trạng quá tải.</p><h2 id="lap-ke-hoach-san-xuat-production-planning" tabindex="-1">Lập kế hoạch sản xuất (Production Planning) <a class="header-anchor" href="#lap-ke-hoach-san-xuat-production-planning" aria-label="Permalink to &quot;Lập kế hoạch sản xuất (Production Planning)&quot;">​</a></h2><p>ABNERP cung cấp công cụ lập kế hoạch sản xuất tổng thể, cho phép lên lịch sản xuất dựa trên đơn đặt hàng, dự báo nhu cầu và mức tồn kho hiện tại. Hệ thống hỗ trợ cả hai phương pháp: sản xuất theo đơn hàng (MTO) và sản xuất theo kế hoạch (MTS), giúp doanh nghiệp linh hoạt trong việc đáp ứng nhu cầu thị trường.</p><h2 id="kiem-soat-chat-luong-quality-control" tabindex="-1">Kiểm soát chất lượng (Quality Control) <a class="header-anchor" href="#kiem-soat-chat-luong-quality-control" aria-label="Permalink to &quot;Kiểm soát chất lượng (Quality Control)&quot;">​</a></h2><p>Mô-đun Sản xuất tích hợp tính năng kiểm soát chất lượng với khả năng tạo các tiêu chuẩn kiểm tra, lấy mẫu và đánh giá. Bạn có thể thiết lập kiểm tra chất lượng tại nhiều điểm trong quy trình sản xuất: nhập nguyên vật liệu, bán thành phẩm và thành phẩm. Hệ thống ghi nhận kết quả kiểm tra và tự động xử lý các lô hàng không đạt tiêu chuẩn.</p>',14)])])}const m=t(c,[["render",o]]);export{p as __pageData,m as default};
